spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 12000;
    var progress = (t % duration) / duration;

    var barW = 180;
    var barH = 22;
    var startX = (W - barW) / 2;
    var centerY1 = H / 2 - 30;
    var centerY2 = H / 2 + 20;

    // Progress stages
    // 0 - 2s: empty bars
    // 2s - 4.5s: fill bar 1 (0.4)
    // 4.5s - 7s: fill bar 2 (0.35)
    // 7s - 9.5s: subdivide top bar and show 0.40
    // 9.5s - 12s: show alignment line & comparison

    var f1 = 0;
    var f2 = 0;
    var isPadded = (progress >= 0.58);

    if (progress >= 0.16) f1 = Math.min(1, (progress - 0.16) / 0.12);
    if (progress >= 0.37) f2 = Math.min(1, (progress - 0.37) / 0.12);
    if (progress >= 0.79) {
      f1 = 1; f2 = 1;
    }

    // Draw Bar 1 (0.4 / 0.40)
    var divisions1 = isPadded ? 100 : 10;
    var filled1 = (isPadded ? 40 : 4) * f1;

    for (var i = 0; i < divisions1; i++) {
      var rx = startX + i * (barW / divisions1);
      ctx.beginPath();
      ctx.rect(rx, centerY1 - barH / 2, barW / divisions1, barH);
      if (i < filled1) {
        ctx.fillStyle = '#3B82F6'; // Blue
      } else {
        ctx.fillStyle = '#1F2937';
      }
      ctx.fill();
      ctx.strokeStyle = isPadded ? '#2563EB' : '#374151';
      ctx.lineWidth = isPadded ? 0.3 : 1.5;
      ctx.stroke();
    }

    // Draw Bar 2 (0.35)
    var divisions2 = 100;
    var filled2 = 35 * f2;
    for (var i = 0; i < divisions2; i++) {
      var rx = startX + i * (barW / divisions2);
      ctx.beginPath();
      ctx.rect(rx, centerY2 - barH / 2, barW / divisions2, barH);
      if (i < filled2) {
        ctx.fillStyle = '#EC4899'; // Pink
      } else {
        ctx.fillStyle = '#1F2937';
      }
      ctx.fill();
      ctx.strokeStyle = '#374151';
      ctx.lineWidth = 0.3;
      ctx.stroke();
    }

    // Labels
    ctx.fillStyle = '#9CA3AF';
    ctx.font = 'bold 12px -apple-system, sans-serif';
    ctx.textAlign = 'right';
    ctx.fillText(isPadded ? '0.40 =' : '0.4 =', startX - 12, centerY1 + 4);
    ctx.fillText('0.35 =', startX - 12, centerY2 + 4);

    ctx.textAlign = 'left';
    ctx.fillText(isPadded ? '40 hundredths' : '4 tenths', startX + barW + 12, centerY1 + 4);
    ctx.fillText('35 hundredths', startX + barW + 12, centerY2 + 4);

    // Alignment line
    if (progress >= 0.79) {
      ctx.beginPath();
      ctx.setLineDash([4, 4]);
      // Draw alignment from end of 0.35 bar (startX + 0.35 * barW)
      var lineX = startX + 0.35 * barW;
      ctx.moveTo(lineX, centerY1 - 20);
      ctx.lineTo(lineX, centerY2 + 20);
      ctx.strokeStyle = '#EF4444';
      ctx.lineWidth = 2;
      ctx.stroke();
      ctx.setLineDash([]);

      // Shaded comparison text
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillStyle = '#10B981';
      ctx.font = 'bold 18px -apple-system, sans-serif';
      ctx.fillText('0.40  >  0.35', W / 2, H - 35);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '12px -apple-system, sans-serif';
      ctx.fillText('40 hundredths is larger than 35 hundredths', W / 2, H - 15);
    } else {
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillStyle = '#F3F4F6';
      ctx.font = 'bold 16px -apple-system, sans-serif';
      ctx.fillText('Compare Tenths and Hundredths', W / 2, H - 35);
    }
  }
};
